// Story 1 — ModalEnter
// ---------------------------------------------------------------------------
export const ModalEnter = {
  name: 'Modal enter',
  render: () => {
    const panels = SYSTEMS.map(s => `
      <div class="system-panel">
        <div class="panel-header" style="background:${s.color};">
          <span class="panel-name">${s.name}</span>
          ${s.isSpring ? '<span style="font-size:9px;color:rgba(255,255,255,0.7);margin-left:4px;">spring</span>' : ''}
        </div>
        <div class="panel-stage">
          <div class="modal-card" id="modal_${s.name}" style="background:${s.color};">
            ${s.name}
          </div>
        </div>
        <div class="panel-meta">
          ${s.description}<br>
          ${s.enterDuration}ms
        </div>
      </div>
    `).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Experimental / Comparison</div>
        <div class="page-subtitle">Modal enter</div>
        <div class="page-desc">
          9 systems, each showing a modal card animating into view using that system's recommended
          enter animation. All animate simultaneously when "Play all" is clicked.
          The visual difference between systems reflects their token values.
        </div>
        <button class="play-btn" id="playAll">Play all</button>
        <div class="grid">${panels}</div>
      </div>
    `;

    el.querySelector('#playAll').addEventListener('click', function() {
      this.disabled = true;
      let done = 0;
      SYSTEMS.forEach(s => {
        const card = el.querySelector(`#modal_${s.name}`);
        card.style.opacity = '0';
        card.style.transform = 'translateX(-50%) translateY(20px)';
        const anim = card.animate(
          [
            { opacity: 0, transform: 'translateX(-50%) translateY(20px)' },
            { opacity: 1, transform: 'translateX(-50%) translateY(0)' },
          ],
          { duration: s.enterDuration, easing: s.enterEasing, fill: 'forwards' }
        );
        anim.onfinish = () => {
          done++;
          if (done === SYSTEMS.length) {
            setTimeout(() => { this.disabled = false; }, 600);
          }
        };
      });
    });

    return el;
  },
};

